import java.sql.*; // import necessary Java packages here: ResultSet, PreparedStatement etc... - do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords) 
public class java_52044_JDBCQueryHandler_A01 { // define your Java classes here: remember the naming convention in style guide, do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords)
    public static Connection getConnection() throws ClassNotFoundException { // define your methods here - remember the naming convention in style guide, do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02/SQLReservedWords)
        String url ="jdbc:mysql://localhost:3306/mydatabase"; // replace with your MySQL server details - remember the naming convention in style guide, do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A12_SQLKeyword)
        String username ="root";//replace  root as per your MySQL server details - remember the naming convention in style guide, do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords)
        String password ="password";//replace  with your MySQL server details - remember the naming convention in style guide, do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords)
        Class.forName("com.mysql.cj.jdbc.Driver"); //loads the driver  - remember using correct package name, do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords)
        return DriverManager.getConnection(url ,username, password); //return the connection object - remember using correct package name from java utils in style guide do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords)
    } 
     public static ResultSet executeQuery(String query, Object...args ) throws SQLException { // define your methods here - remember the naming convention in style guide do NOT use "oracle." prefixed ones; they are reserved for Oracle SQL and should be avoided unless you have a specific reason to avoid them (A02_SQLReservedWords)
        Connection conn = getConnection(); 
        PreparedStatement pstmt=conn.prepareStatement(query); // prepare the statement using query string & placeholders - remember not to use oracle prefixed ones and do NOT put "select *" at start of queries or end it with a semicolon if they are used in loops, as this could be an error (A01_BrokenAccessControl)
        for(int i=0;i<args.length ;i++){ // loop through the args and set each argument to statement - remember not using Oracle prefixed ones do NOT use "select *" at start of queries or end it with a semicolon if they are used in loops, as this could be an error (A12_SQLInjection)
            pstmt.setObject(i+1 ,args[i]); // set each argument to statement - remember not using Oracle prefixed ones do NOT use "select *" at start of queries or end it with a semicolon if they are used in loops, as this could be an error (A02_SQLReservedWords)
        }  pstmt.executeUpdate(); // execute the prepared statement - remember not using Oracle prefixed ones do NOT use "select *" at start of queries or end it with a semicolon if they are used in loops, as this could be an error (A02_SQLReservedWords)
        return pstmt.executeQuery(); // get the result set - remember not using Oracle prefixed ones do NOT use "select *" at start of queries or end it with a semicolon if they are used in loops, as this could be an error (A02_SQLReservedWords)
    } 
}